INSERT INTO public.changelog (version, title, body) VALUES (
  '1.4.0',
  'ابزار مداد و طراحی روی سند + رفع پنهان‌شدن خط اول',
  E'ویژگی‌های جدید:\n• افزودن ابزار «مداد» به بخش ادیت با انیمیشن ملایم و لوپ (شکل مداد در حالت فعال به آیکون T تبدیل می‌شود).\n• هفت نوع قلم قابل انتخاب: مداد، خودکار، ماژیک، هایلایتر، قلم‌مو، خودنویس، مداد رنگی — هرکدام با ظاهر و ضخامت مخصوص خود.\n• امکان انتخاب رنگ قلم از پالت آماده.\n• دکمه «صاف کن» با کمک الگوریتم هوشمند، لرزش دست/موس را کاهش می‌دهد و خطوط را نرم‌تر می‌کند.\n• دکمه‌های Undo، پاک کردن کامل و خروج از حالت طراحی.\n\nرفع اشکال:\n• خط اول متن که پشت نوار ابزار پنهان می‌شد اکنون کامل قابل مشاهده است.'
);